  ('social-worker-moex-00551', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '我國社會工作師法制度是專業發展的重要里程碑，有關社會工作師證照建立過程，下列敘述何者 錯誤？', '["為回應當時省市政府約聘社會工作者無法納編問題", "第一份社會工作師法草案由內政部委託社會工作專業協會承辦起草，邀請學術界、實務界專家 共同參與", "第一個社會工作師職業公會於1998年在臺北市成立", "於1999年公布施行社會工作師法，後續訂定社會工作倫理原則，作為社會工作實務指引與規範"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "bee498742522", "answer_pdf_sha1": "c77af4f0ebe1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
