  ('social-worker-moex-00554', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作依據人在環境中的根本假設，視案主的情況和需要做環境調整，下列何者不屬於環境調整？', '["在協助受虐兒童時，增強其施虐家長的親職能力並協助媒合穩定工作", "在提供家暴相對人的服務時，協助其強化情緒管理的能力", "協助受暴婦女時，將其從有危險的家中帶至安全的緊急安置處所", "改善長照機構的方案和設備，以使機構老人能獲得更好的照顧品質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "bee498742522", "answer_pdf_sha1": "c77af4f0ebe1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
