  ('social-worker-moex-00556', 'social-worker', 'social-worker-moex-112-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列對於社區及社區工作的敘述，何者錯誤？', '["社區工作者須具前瞻眼光與領導能力，其責任在為社區擬定發展方針，以改造社區使居民獲得 更好的生活", "社區主要可包含人民、地方或地理疆界，以及社會互動、認同等要素", "社區工作是一種互動的過程，人們藉由從事集體行動來改善他們的社區，經由社區組織的運作， 達到社區增權", "社區工作發展的歷史，可追溯自英美所開展的睦鄰組織運動（SocialSettlementMovement）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:04+00:00", "source_pdf_sha1": "bee498742522", "answer_pdf_sha1": "c77af4f0ebe1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112030", "c": "103", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "112", "exam_name": "112年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
